const _taxableInc=Math.max(0,(s.monthly_revenue||0)-(s.cogs||0)-(s.operating_expenses||0));
const monthlyReserve=(sep&&s._completed_actions.includes('monthly_tax_reserve'))?Math.round(_taxableInc*(s.tax_rate||0.25)):0;
if(monthlyReserve)s.tax_reserve=(s.tax_reserve||0)+monthlyReserve;
const insFunding=(s._completed_actions&&s._completed_actions.includes('setup_accumulation_policy')&&s._auto_fund_insurance)?Math.round(Math.min((s.monthly_revenue||0)*0.15,this.calcBusinessLevel()*5000)):0; // accumulation IUL funding (aggressive, scales with revenue) is a personal expense, covered by the owner draw
