if(s.personal_cash<0){const pc=Math.min(-s.personal_cash,s.available_credit||0);if(pc>0){const fee=Math.round(pc*0.03);s.available_credit-=(pc+fee);s.total_debt=(s.total_debt||0)+pc+fee;s.personal_cash+=pc;}} // personal credit as last resort
